function audit_search(state: DashboardState, dispatch: DashboardDispatch): ReactNode {
  const results = (state.values['audit_log'] as readonly { id: string; label: string }[] | undefined) ?? [];
  return (
    <section data-explore='audit_search' data-prompt='Audit log' data-source='audit_log'>
      <input
        type='search'
        placeholder='Search events...'
        defaultValue={String(state.drafts['audit_search'] ?? '')}
        onChange={(e) => dispatch({ verb: 'EXPLORE', id: 'audit_search', action: 'query', payload: e.currentTarget.value })}
      />
      <ul role='listbox'>
        {results.map((r) => (
          <li key={r.id} data-result-id={r.id}>{r.label}</li>
        ))}
      </ul>
    </section>
  );
}

