function admin_setup(state: DashboardState, dispatch: DashboardDispatch): ReactNode {
  const current = String(state.selections['admin_setup'] ?? 'profile');
  return (
    <nav data-onboard='admin_setup' data-prompt='New admin setup' data-progress-type='step'>
      <ol>
        <li data-step='profile' data-active={String(current === 'profile')}>Profile</li>
        <li data-step='permissions' data-active={String(current === 'permissions')}>Permissions</li>
        <li data-step='review' data-active={String(current === 'review')}>Review</li>
      </ol>
      <button type='button' data-step-action='advance' onClick={() => dispatch({ verb: 'ONBOARD', id: 'admin_setup', action: 'advance', payload: current })}>Next</button>
      <button type='button' data-step-action='skip' onClick={() => dispatch({ verb: 'ONBOARD', id: 'admin_setup', action: 'skip', payload: current })}>Skip</button>
    </nav>
  );
}

